import axios from 'axios';

// Build API base URL using the current host so the frontend works when accessed
// via the machine IP (e.g. http://172.31.182.178:3000)
const backendHost = window?.location?.hostname || 'localhost';
const API = axios.create({ baseURL: `http://${backendHost}:8000/api/` });

function getToken(){
  return localStorage.getItem('access');
}

API.interceptors.request.use(config => {
  const token = getToken();
  if(token){
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export async function login(username, password){
  const url = `http://${backendHost}:8000/api/auth/login/`;
  const res = await axios.post(url, {username, password});
  localStorage.setItem('access', res.data.access);
  localStorage.setItem('refresh', res.data.refresh);
  return res.data;
}

export async function register(data){
  const res = await API.post('auth/register/', data);
  return res.data;
}

export async function getMe(){
  const token = getToken();
  if (!token) return null;

  try{
    const res = await API.get('auth/me/');
    return res.data;
  }catch(e){
    // Token invalid or expired — clear storage to force re-login
    localStorage.removeItem('access');
    localStorage.removeItem('refresh');
    return null;
  }
}

export async function getProjects(){
  const res = await API.get('projects/');
  return res.data;
}

export async function getProject(id){
  const res = await API.get(`projects/${id}/`);
  return res.data;
}

export async function createProject(payload){
  const res = await API.post('projects/', payload);
  return res.data;
}

export async function getNotifications(){
  const res = await API.get('notifications/');
  return res.data;
}

export async function createTask(payload){
  const res = await API.post('tasks/', payload);
  return res.data;
}

export async function updateTask(id, payload){
  const res = await API.patch(`tasks/${id}/`, payload);
  return res.data;
}

export async function addComment(payload){
  const res = await API.post('comments/', payload);
  return res.data;
}

export default API;
